function initSwiperProducts() {
  const swiperEl = document.querySelector(".swiper-products");
  if (!swiperEl || typeof Swiper === "undefined") return;

  swiperEl.setAttribute("tabindex", "0");

  const swiper = new Swiper(swiperEl, {
    loop: false,
    speed: 500,
    slidesPerView: "auto",
    spaceBetween: 24,
    centeredSlides: true,
    centeredSlidesBounds: true,
    slideToClickedSlide: true,
    allowTouchMove: true,
    slidesOffsetAfter: 64,
    keyboard: {
      enabled: true,
      onlyInViewport: true,
      pageUpDown: true
    },
    a11y: {
      enabled: true
    },
    pagination: {
      el: ".swiper-pagination",
      clickable: true
    },
    navigation: {
      nextEl: ".product_next",
      prevEl: ".product_prev"
    },
    breakpoints: {
      768: {
        slidesPerView: "auto",
        spaceBetween: 24,
        centeredSlides: false,
        centeredSlidesBounds: false
      },
      1280: {
        slidesPerView: "auto",
        spaceBetween: 32,
        centeredSlides: false,
        slidesOffsetAfter: 228,
        centeredSlidesBounds: false
      }
    }
  });

  swiperEl.querySelectorAll(".swiper-slide.is--product").forEach((slide, i) => {
    slide.setAttribute("tabindex", "0");
    slide.addEventListener("keydown", (e) => {
      if (e.key === "Enter" || e.key === " ") {
        e.preventDefault();
        swiper.slideTo(i);
      }
    });
  });
}

function initSwiperTeam() {
  const swiperEl = document.querySelector(".swiper-team");
  if (!swiperEl || typeof Swiper === "undefined") return;

  new Swiper(swiperEl, {
    loop: false,
    speed: 700,
    slidesPerView: "auto",
    slidesPerGroup: 1,
    spaceBetween: 16,
    centeredSlides: true,
    centeredSlidesBounds: true,
    slideToClickedSlide: true,
    allowTouchMove: true,
    watchOverflow: true,
    observer: true,
    observeParents: true,
    navigation: {
      nextEl: ".team-next",
      prevEl: ".team-prev"
    },
    breakpoints: {
      768: {
        slidesPerView: "auto",
        spaceBetween: 16,
      },
      
      1280: {
        slidesPerView: "auto",
        spaceBetween: 16,
      },
      
      1440: {
        slidesPerView: "auto",
        spaceBetween: 16,
      },
      
      1920: {
        slidesPerView: "auto",
        spaceBetween: 16,
      }
    }
  });
}

function initTeamCardZoom() {
  if (typeof gsap === "undefined") return;

  const teamCards = document.querySelectorAll(".slide_inner.is--team");

  teamCards.forEach((card) => {
    const img = card.querySelector(".people_img");

    card.addEventListener("mouseenter", () => {
      if (img) {
        gsap.to(img, {
          scale: 1.05,
          duration: 0.4,
          ease: "power3.out"
        });
      }
    });

    card.addEventListener("mouseleave", () => {
      if (img) {
        gsap.to(img, {
          scale: 1,
          duration: 0.4,
          ease: "power3.out"
        });
      }
    });
  });
}

function initAll() {
  initSwiperProducts();
  initSwiperTeam();
  initTeamCardZoom();
}

if (document.readyState === "loading") {
  document.addEventListener("DOMContentLoaded", initAll);
} else {
  initAll();
}
